# Search quran for verses containing this snippet prefix
matches = []
for v in quran_data:
    text = v.get("ayah_text") or v.get("text") or ""
    if not text:
        continue
    if normalize(text).startswith(norm_snip):
        matches.append(text)

len(matches)

# Search hadith for beginning with this snippet after normalization
hadith_matches = []
for h in hadith_data:
    text = h.get("hadithTxt") or h.get("Matn") or ""
    if not text:
        continue
    if normalize(text).startswith(norm_snip):
        hadith_matches.append(text)
len(hadith_matches)

# Filter matches for those containing words related to fire or Ibrahim
def contains_keywords(text, keywords):
    nt = normalize(text)
    return all(k in nt for k in keywords)

candidates_related = []
for text in matches:
    if contains_keywords(text, ["ابراهيم"]) or contains_keywords(text, ["نار"]) or contains_keywords(text, ["حريق"]) or contains_keywords(text, ["بردا"]) or contains_keywords(text, ["سلاما"]):
        candidates_related.append(text)
